const sectionBPartBData = [
  // ═══════════════════════════════════════════════════════════════
  // PAST PAPERS (from 0455 w21-w25, s21/s23-s25, m21-m25 QP+MS)
  // ═══════════════════════════════════════════════════════════════
  // --- W21 ---
  { "id": "SBb_PP_w21_Q2b", "case": "A number of countries, including Morocco, capture water from fog. Water is used in the primary, secondary and tertiary sectors. In recent years, Morocco has increased the quantity and quality of its resources and has moved more of them into the tertiary sector. The quantity, quality and composition of a country's resources are influenced by a number of factors, including its birth rate. Morocco's birth rate fell from 19.9 in 2016 to 18.7 in 2018.", "q": "Explain, with examples, the difference between the secondary sector and the tertiary sector.", "ans": [[["Secondary sector covers manufacturing / construction", "converts primary products into finished goods / e.g. car industry"]], [["Tertiary sector covers services", "final stage of production / e.g. insurance"]]], "concept": "0455 w21/22 Q2(b). MS: Secondary (1)+example (1); Tertiary (1)+example (1)." },
  { "id": "SBb_PP_w21_Q3b", "case": "Two of Uzbekistan's main industries are cotton and gas. Uzbekistan is the world's seventh largest producer, and fifth largest exporter, of cotton. The Uzbek government has tried to influence the cotton industry's price elasticity of supply. It has also nearly ended the use of child labour in cotton production. The country's output of gas increased by 7% in 2018 and its average cost of gas production fell.", "q": "Explain two advantages to an economy of ending child labour.", "ans": [[["Enable children to be educated", "raise productivity / workers' skills / literacy / long run economic growth"], ["Improve children's health", "increase life expectancy / raise living standards"], ["Reduce cycle of poverty", "children will later gain higher paid jobs"], ["Raise wages", "reduced supply of cheap labour"], ["Increase job opportunities for adults", "lower unemployment / more employment of adults"]], [["Enable children to be educated", "raise productivity / workers' skills / literacy / long run economic growth"], ["Improve children's health", "increase life expectancy / raise living standards"], ["Reduce cycle of poverty", "children will later gain higher paid jobs"], ["Raise wages", "reduced supply of cheap labour"], ["Increase job opportunities for adults", "lower unemployment / more employment of adults"]]], "concept": "0455 w21 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_w21_Q4b", "case": "In Tunisia, resource allocation decisions are made by both the public sector and private sector. Tunisia's GDP increased from 2014 to 2018 but its households saved less. Income levels can be affected by changes in trade union activity and the foreign exchange rate. From 2014 to 2018, Tunisia experienced a number of strikes organised by its largest trade union. There was also a significant fall in its foreign exchange rate.", "q": "Explain two reasons why households may save less even though their income has increased.", "ans": [[["Fall in rate of interest", "reduce return from saving / spend or borrow rather than save"], ["Inflation", "spend more now before prices rise / reduce real rate of interest"], ["Increase in confidence", "less motive to save for hard times / less concerned about unemployment"], ["Greater consumption opportunities", "new products / lower prices / can afford education healthcare"]], [["Fall in rate of interest", "reduce return from saving / spend or borrow rather than save"], ["Inflation", "spend more now before prices rise / reduce real rate of interest"], ["Increase in confidence", "less motive to save for hard times / less concerned about unemployment"], ["Greater consumption opportunities", "new products / lower prices / can afford education healthcare"]]], "concept": "0455 w21 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_w21_Q5b", "case": "The US operates a mainly market economic system. Life expectancy in the US fell in 2017, for the third year in a row. Although the US has a high GDP per head, it also has a high level of income inequality. The poor benefited from the US's low and stable inflation rate. The government's supply-side policy measures were partly responsible for reducing inflationary pressure.", "q": "Explain two advantages of a market economic system.", "ans": [[["Consumer sovereignty", "consumers decide what goods and services are produced"], ["Low prices", "due to competition"], ["High quality", "due to innovation"], ["Consumer choice", "variety of products produced"], ["Greater efficiency", "due to profit motive"], ["Automatic adjustment", "price mechanism / quick response to demand and supply"]], [["Consumer sovereignty", "consumers decide what goods and services are produced"], ["Low prices", "due to competition"], ["High quality", "due to innovation"], ["Consumer choice", "variety of products produced"], ["Greater efficiency", "due to profit motive"], ["Automatic adjustment", "price mechanism / quick response to demand and supply"]]], "concept": "0455 w21 Q5(b). MS: any two + explanation." },
  // --- W22 ---
  { "id": "SBb_PP_w22_Q2b", "case": "The economic problem results in choices and opportunity cost. People have to decide what job to do and where to live. In recent years Australia has recruited teachers from a number of countries including Canada, the UK and the US. Most of these teachers specialise in a single subject.", "q": "Explain the economic problem and why it is always likely to exist.", "ans": [[["Economic problem is finite resources", "and infinite wants / scarcity"]], [["Always likely to exist", "wants grow faster than resources / population increasing / resources depleted"]]], "concept": "0455 w22 Q2(b). MS: definition (2) + why exists (2)." },
  { "id": "SBb_PP_w22_Q3b", "case": "In 2019, Russia had an unemployment rate of 4.6%. Russia experienced full employment in the past. Its government wants unemployment to be lower. In 2018, the Russian government cut its spending which may have increased poverty. In both 2018 and 2019, the government did not change its income tax rate. Russia operates a proportional tax rate system.", "q": "Explain the difference between a proportional income tax system and a progressive income tax system.", "ans": [[["Proportional takes same percentage from all", "tax rate does not change as income changes / no effect on distribution"]], [["Progressive takes larger percentage from rich", "tax rate increases as income increases / redistributes from rich to poor"]]], "concept": "0455 w22 Q3(b). MS: proportional (2) + progressive (2)." },
  { "id": "SBb_PP_w22_Q4b", "case": "Advances in technology have changed how trees (wood) are cut down, transported and used in the manufacture of furniture, such as tables. Wood is in inelastic supply. Wood can be supplied in all economic systems. However, public goods are not supplied in a market economic system.", "q": "Explain why public goods would not be supplied in a market economic system.", "ans": [[["Non-excludable", "cannot stop non-payers from consuming / free rider problem"]], [["Non-rival", "if supplied for one supplied for everyone / cannot charge additional consumers"], ["Private firms profit motivated", "cannot get revenue / would make a loss"]], [["Non-excludable", "cannot stop non-payers from consuming / free rider problem"], ["Non-rival", "if supplied for one supplied for everyone / cannot charge additional consumers"], ["Private firms profit motivated", "cannot get revenue / would make a loss"]]], "concept": "0455 w22 Q4(b). MS: non-excludable, non-rival, profit motive." },
  { "id": "SBb_PP_w22_Q5b", "case": "While 15% of US exports go to Mexico, 80% of Mexico's exports go to the US. In 2019, the US government imposed some methods of protection to reduce imports from Mexico. This US action caused a fall in Mexico's foreign exchange rate. Despite a rise in its inflation rate, Mexico's central bank reduced the rate of interest from 7.75% at the end of 2019 to 6.5% in March 2020.", "q": "Explain two reasons why a government may want to reduce imports.", "ans": [[["Improve current account / balance of payments", "reduce deficit / increase net exports"], ["Increase GDP / economic growth", "switch demand to domestic products / protect domestic firms / infant industries"], ["Prevent dumping", "sale of goods at below cost / predatory prices"], ["Increase employment", "raise living standards"], ["Reduce dependence on other countries", "risk of supplies cut off"]], [["Improve current account / balance of payments", "reduce deficit / increase net exports"], ["Increase GDP / economic growth", "switch demand to domestic products / protect domestic firms / infant industries"], ["Prevent dumping", "sale of goods at below cost / predatory prices"], ["Increase employment", "raise living standards"], ["Reduce dependence on other countries", "risk of supplies cut off"]]], "concept": "0455 w22 Q5(b). MS: any two + explanation." },
  // --- W23 ---
  { "id": "SBb_PP_w23_Q2b", "case": "Botswana had an average economic growth rate of 3.8% between 2015 and 2019 compared to a global average of 2.8%. Over this period, the country experienced a low inflation rate and a move away from protectionism.", "q": "Explain two reasons why a low inflation rate may increase a country's economic growth rate.", "ans": [[["Make products internationally competitive", "sell more exports / buy fewer imports / increase demand for output"], ["Create greater certainty", "encourage investment / attract MNCs / firms more willing to invest"], ["Keep increase in costs low", "reduce wage claims / reduce cost-push pressure"], ["Increase confidence", "may increase demand / increase profits"]], [["Make products internationally competitive", "sell more exports / buy fewer imports / increase demand for output"], ["Create greater certainty", "encourage investment / attract MNCs / firms more willing to invest"], ["Keep increase in costs low", "reduce wage claims / reduce cost-push pressure"], ["Increase confidence", "may increase demand / increase profits"]]], "concept": "0455 w23/22 Q2(b). MS: any two of four reasons + explanations. Competitive→exports; certainty→investment; costs→wages; confidence→demand." },
  { "id": "SBb_PP_w23_Q3b", "case": "In 2020, some firms in Suriname stopped production. The reduction in the country's output resulted in a rise in its unemployment rate. In 2021, the number of firms in some markets fell again, but this time output was rising.", "q": "Explain two types of unemployment.", "ans": [[["Frictional unemployment", "workers in between jobs / temporarily unemployed while searching"], ["Structural unemployment", "skills not matching vacancies / lack of labour mobility / changes in demand and supply"], ["Cyclical / demand-deficient unemployment", "lack of total demand / occurs during a recession"]], [["Frictional unemployment", "workers in between jobs / temporarily unemployed while searching"], ["Structural unemployment", "skills not matching vacancies / lack of labour mobility / changes in demand and supply"], ["Cyclical / demand-deficient unemployment", "lack of total demand / occurs during a recession"]]], "concept": "0455 w23/22 Q3(b). MS: any two types + explanation each. Frictional, structural, cyclical." },
  { "id": "SBb_PP_w23_Q4b", "case": "US farmers are influenced by the subsidies the government provides for the production of selected food items. Some people are reluctant to become farm workers as they think living standards are low in rural areas.", "q": "Explain two reasons why a government may subsidise food production.", "ans": [[["Increase output / overcome shortage", "ensure enough food is produced / food security"], ["Reduce price / make food affordable", "help consumers / reduce poverty / basic necessity"], ["Increase incomes of farmers", "raise living standards / stop farmers going out of business"], ["Increase employment", "help in rural areas / more jobs"]], [["Increase output / overcome shortage", "ensure enough food is produced / food security"], ["Reduce price / make food affordable", "help consumers / reduce poverty / basic necessity"], ["Increase incomes of farmers", "raise living standards / stop farmers going out of business"], ["Increase employment", "help in rural areas / more jobs"]]], "concept": "0455 w23/22 Q4(b). MS: any two of output, price, incomes, employment, imports." },
  { "id": "SBb_PP_w23_Q5b", "case": "Singapore managed to increase its exports of goods and services. Some Singaporean markets moved from disequilibrium to equilibrium in 2020.", "q": "Explain how a market moves from disequilibrium to equilibrium.", "ans": [[["If demand greater than supply / shortage / excess demand", "price will rise"]], [["If supply greater than demand / surplus / excess supply", "price will fall"]]], "concept": "0455 w23/22 Q5(b). MS: shortage→price rises (1+1); surplus→price falls (1+1)." },
  // --- W24 ---
  { "id": "SBb_PP_w24_Q2b", "case": "In 2021, the production point on the UK's production possibility curve (PPC) changed. Average wages increased. The average annual wage of a waiter was $23,580 while that of a chief executive of a large commercial bank was $1,617,000. A rise in wages enables people to eat in restaurants more often. In 2021, the UK government signed free trade agreements, removing import restrictions, with a number of countries.", "q": "Explain two reasons why someone may switch from eating in one restaurant to eating in another restaurant.", "ans": [[["Change in prices", "lower price more affordable / substitutes / save money"], ["Change in quality", "better ingredients / cleanliness / service / menu"], ["Change in convenience", "opening hours / location"], ["Change in income", "enable eating in more expensive restaurants"], ["Consumer tastes", "e.g. switch to vegan restaurant"], ["Advertising", "attract or persuade customers"]], [["Change in prices", "lower price more affordable / substitutes / save money"], ["Change in quality", "better ingredients / cleanliness / service / menu"], ["Change in convenience", "opening hours / location"], ["Change in income", "enable eating in more expensive restaurants"], ["Consumer tastes", "e.g. switch to vegan restaurant"], ["Advertising", "attract or persuade customers"]]], "concept": "0455 w24 Q2(b). MS: any two + explanation." },
  { "id": "SBb_PP_w24_Q3b", "case": "The central bank of Madagascar intervenes in the country's foreign exchange market. Madagascar has a largely market economic system. Nearly 70% of Madagascar's population live in poverty. Most of the country's industries are labour-intensive. In 2020, Madagascar had an economic growth rate of 6% and a deficit on the current account of its balance of payments of $0.6bn.", "q": "Explain two reasons why a firm may adopt labour-intensive production.", "ans": [[["Labour low in price / wages low", "cheaper than capital / high supply of labour"], ["Labour productive / efficient", "employment profitable / low costs of production"], ["Government may subsidise employment", "to reduce unemployment"], ["Firm provides personal services", "individual attention required"], ["Labour more creative / adaptable", "high quality products / improve methods"]], [["Labour low in price / wages low", "cheaper than capital / high supply of labour"], ["Labour productive / efficient", "employment profitable / low costs of production"], ["Government may subsidise employment", "to reduce unemployment"], ["Firm provides personal services", "individual attention required"], ["Labour more creative / adaptable", "high quality products / improve methods"]]], "concept": "0455 w24 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_w24_Q4b", "case": "In 2021, there were extensions and contractions in demand for a number of South African products. A South African court stopped an MNC exploring for oil along South Africa's coastline. South Africa experienced an increase in output, driven largely by the growth in its tertiary sector. However, its unemployment rate was 35%, a long way from full employment.", "q": "Explain two external costs that may be caused by exploring for oil.", "ans": [[["Air pollution", "reduction in air quality / climate change / reduced health"], ["Noise pollution", "disturbing sleep"], ["Water pollution / oil spillage", "damage health"], ["Damage to natural environment", "destroy wildlife habitats / deforestation"], ["Reduce tourism", "lower employment"]], [["Air pollution", "reduction in air quality / climate change / reduced health"], ["Noise pollution", "disturbing sleep"], ["Water pollution / oil spillage", "damage health"], ["Damage to natural environment", "destroy wildlife habitats / deforestation"], ["Reduce tourism", "lower employment"]]], "concept": "0455 w24 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_w24_Q5b", "case": "Peru's third largest industry is tourism. There are many firms in the Peruvian tourism industry. Another major industry in Peru is fruit farming. In recent years, trade union membership in the Peruvian fruit-farming industry has increased.", "q": "Explain two reasons why countries with a good transport system often have a high GDP.", "ans": [[["Lower firms' costs", "cheaper to move goods / more efficient / increase exports"], ["Reduce wastage", "food arrives fresh / higher profits"], ["Increase labour mobility", "reduce unemployment / increase productivity"], ["Increase tourism earnings", "easier to move around country"], ["Attract MNCs / FDI", "increase employment / productive capacity"]], [["Lower firms' costs", "cheaper to move goods / more efficient / increase exports"], ["Reduce wastage", "food arrives fresh / higher profits"], ["Increase labour mobility", "reduce unemployment / increase productivity"], ["Increase tourism earnings", "easier to move around country"], ["Attract MNCs / FDI", "increase employment / productive capacity"]]], "concept": "0455 w24 Q5(b). MS: any two + explanation." },
  // --- W25 ---
  { "id": "SBb_PP_w25_Q2b", "case": "Some markets in Belgium are in equilibrium. The country produces a wide range of goods with different degrees of price elasticity of demand. The Belgian Government wants the economy to move to a production possibility point beyond its current PPC. Belgium's scientific industry is one industry which is doing well. Workers in this industry are highly specialised.", "q": "Explain two ways an economy could reach a point outside its current PPC.", "ans": [[["Increase investment", "devote more resources to capital goods"], ["Encourage immigration", "increase size of labour force"], ["Land reclamation", "create more land for e.g. crops"], ["Increase education and training", "raise quality / productivity of labour"], ["Increase R&D / new technology", "increase productivity of capital"], ["Discovery of resources", "enables extra output"]], [["Increase investment", "devote more resources to capital goods"], ["Encourage immigration", "increase size of labour force"], ["Land reclamation", "create more land for e.g. crops"], ["Increase education and training", "raise quality / productivity of labour"], ["Increase R&D / new technology", "increase productivity of capital"], ["Discovery of resources", "enables extra output"]]], "concept": "0455 w25 Q2(b). MS: any two + explanation." },
  { "id": "SBb_PP_w25_Q3b", "case": "In April 2023, a French cosmetics firm merged with an Australian cosmetics firm. The merger will lower average total cost through greater internal economies of scale. A key aim is to make production more sustainable by using raw materials from renewable sources. In most countries, cosmetics including perfume are taxed at a higher rate than food.", "q": "Explain how using renewable raw materials may affect a firm's profits.", "ans": [[["May reduce profits - renewable more expensive", "increase costs of production"], ["May increase profits - advertise sustainability", "raise demand / improve image / increase sales"], ["May increase profits - subsidised", "cheaper in long run"], ["May increase profits - resources not depleted", "constant supply of raw materials"]], [["May reduce profits - renewable more expensive", "increase costs of production"], ["May increase profits - advertise sustainability", "raise demand / improve image / increase sales"], ["May increase profits - subsidised", "cheaper in long run"], ["May increase profits - resources not depleted", "constant supply of raw materials"]]], "concept": "0455 w25 Q3(b). MS: profits may rise or fall - both credited with explanation." },
  { "id": "SBb_PP_w25_Q4b", "case": "There are several policy measures a central bank or government can use to reduce unemployment. One measure is to increase spending on building houses. The Federal Reserve has two main aims: maintain price stability and achieve full employment. Some central banks also have economic growth as a target.", "q": "Explain two benefits to an economy of full employment.", "ans": [[["High output / GDP", "maximum use of labour resource"], ["High tax revenue", "government can spend on education healthcare"], ["Low spending on benefits", "keep taxes low / money for other things"], ["Low poverty", "enable purchase of necessities / raise living standards"]], [["High output / GDP", "maximum use of labour resource"], ["High tax revenue", "government can spend on education healthcare"], ["Low spending on benefits", "keep taxes low / money for other things"], ["Low poverty", "enable purchase of necessities / raise living standards"]]], "concept": "0455 w25 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_w25_Q5b", "case": "Some countries engage in dumping by selling their products at less than cost price in Cambodia. The Cambodian Government wants to become a high-income economy by 2050. It uses fiscal, monetary and supply-side policies. Cambodia subsidises some infant industries. The country has one of the world's largest current account deficits (as a percentage of GDP).", "q": "Explain two differences between monetary policy and supply-side policy.", "ans": [[["Monetary by central bank", "supply-side by government"], ["Monetary influences demand", "supply-side aims to increase supply"], ["Different measures", "e.g. interest rates vs privatisation"], ["Monetary short-term impact", "supply-side takes longer"]], [["Monetary by central bank", "supply-side by government"], ["Monetary influences demand", "supply-side aims to increase supply"], ["Different measures", "e.g. interest rates vs privatisation"], ["Monetary short-term impact", "supply-side takes longer"]]], "concept": "0455 w25 Q5(b). MS: any two differences + explanation." },
  // --- S21 ---
  { "id": "SBb_PP_s21_Q2b", "case": "Nearly one million people in Cairo live in crowded, unhealthy housing. One reason is unemployment. Other citizens live in luxury.", "q": "Explain how frictional unemployment differs from cyclical unemployment.", "ans": [[["Frictional: in between jobs", "waiting for better job / seasonal / short-term contract / lack of information / may exist at full employment"]], [["Cyclical: lack of total demand", "more unemployed than vacancies / recession / may need government action"]]], "concept": "0455 s21 Q2(b). MS: frictional (2) + cyclical (2)." },
  { "id": "SBb_PP_s21_Q3b", "case": "Consumers in Uruguay are eating more processed foods. Factors of production, including enterprise, have responded. Firms in the processed food industry have become more capital-intensive. All of Uruguay's industries were affected by the rise in its inflation rate, from 6.2% in 2017 to 7.7% in 2018.", "q": "Explain the influence of opportunity cost on consumers' decisions.", "ans": [[["Opportunity cost is next best alternative forgone", "consumers have limited income / time"]], [["Have to make choices", "cannot have everything / if buy one product give up another"]]], "concept": "0455 s21 Q3(b). MS: definition (2) + influence (2)." },
  { "id": "SBb_PP_s21_Q4b", "case": "Turkey's birth rate is falling which is likely to reduce its supply of labour. However, improvements in the quality of labour and the increase in foreign MNCs operating in Turkey may help the economy avoid a recession. One reason why economists are worried that a recession may occur is an expected rise in the interest rate.", "q": "Explain two causes of an increase in the quality of labour in a country.", "ans": [[["Improvements in education", "qualifications / knowledge"], ["Improvements in training", "increasing skills"], ["Improvements in healthcare", "workers stronger"], ["Improvements in nutrition", "workers work harder"], ["Immigration of skilled workers", "bring expertise"]], [["Improvements in education", "qualifications / knowledge"], ["Improvements in training", "increasing skills"], ["Improvements in healthcare", "workers stronger"], ["Improvements in nutrition", "workers work harder"], ["Immigration of skilled workers", "bring expertise"]]], "concept": "0455 s21 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_s21_Q5b", "case": "The money supply in Bangladesh increased every year from 2010 to 2018. Changes in the money supply affect macroeconomic aims. There have been few mergers between commercial banks in Bangladesh, although its banks are larger than many of its other firms.", "q": "Explain two reasons why commercial banks may want to merge.", "ans": [[["Greater market power / share / monopoly / less competition", "eliminate competitor / greater range of services / can raise price / charge more / charge higher / consumers cannot switch"], ["Economies of scale", "lower costs / reducing costs / reduce costs / higher profit / spread fixed costs / merging branches reducing fixed cost"], ["Operate in more countries", "access new markets"], ["Rationalisation", "eliminate duplication / raise efficiency"]], [["Greater market power / share / monopoly / less competition", "eliminate competitor / greater range of services / can raise price / charge more / charge higher / consumers cannot switch"], ["Economies of scale", "lower costs / reducing costs / reduce costs / higher profit / spread fixed costs / merging branches reducing fixed cost"], ["Operate in more countries", "access new markets"], ["Rationalisation", "eliminate duplication / raise efficiency"]]], "concept": "0455 s21 Q5(b). MS: any two + explanation. CR/ER: credit alternatives." },
  // --- S23 ---
  { "id": "SBb_PP_s23_Q2b", "case": "In 2020, the largest Thai commercial bank merged with a smaller Thai commercial bank. It was expected that the merger would affect the price charged for bank services and the amount that would be lent. Thai commercial banks operate in the private sector.", "q": "Explain two reasons why a merger may result in higher prices for consumers.", "ans": [[["More market power / less competition", "can raise price / consumers cannot switch / demand more inelastic"], ["Diseconomies of scale", "higher costs / raise prices"], ["Cost of merger", "retraining / redundancies / raise price to cover cost"]], [["More market power / less competition", "can raise price / consumers cannot switch / demand more inelastic"], ["Diseconomies of scale", "higher costs / raise prices"], ["Cost of merger", "retraining / redundancies / raise price to cover cost"]]], "concept": "0455 s23 Q2(b). MS: any two + explanation." },
  { "id": "SBb_PP_s23_Q3b", "case": "Canada's private sector firms have a number of different objectives. There has been increased investment with firms buying more capital goods. The quantity and quality of land used by these firms, including farms, has increased. In 2021, the Canadian government encouraged higher investment and aimed to prevent a rise in unemployment.", "q": "Explain one reason why the quantity of land may increase and one reason why the quality of land may increase.", "ans": [[["Quantity: reclamation", "creating land from sea"], ["Quantity: discovery of resources", "e.g. oil"], ["Quantity: reduction in flooding", "avoid soil erosion"]], [["Quality: use of fertilisers", "raise productivity / fertility"], ["Quality: reduction in pollution", "prevent damage"], ["Quality: better equipment / technology", "raise productivity"]]], "concept": "0455 s23 Q3(b). MS: one quantity (2) + one quality (2)." },
  { "id": "SBb_PP_s23_Q4b", "case": "In 2020, Australia had a high national minimum wage (NMW). The NMW is received by some people who work on Australian dairy farms. Australia produces milk and soft drinks. Milk is purchased by some people as an alternative to soft drinks. Some dairy farms and small firms went out of business in 2020. The year saw an increase in the value of the country's floating foreign exchange rate.", "q": "Explain two causes of an increase in the value of a country's floating foreign exchange rate.", "ans": [[["Increase in demand for currency", "rise in exports / exports exceed imports / current account surplus"], ["Higher rate of interest", "attracts hot money flows"], ["Decrease in supply of currency", "fall in imports"], ["Speculation", "currency expected to rise"]], [["Increase in demand for currency", "rise in exports / exports exceed imports / current account surplus"], ["Higher rate of interest", "attracts hot money flows"], ["Decrease in supply of currency", "fall in imports"], ["Speculation", "currency expected to rise"]]], "concept": "0455 s23 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_s23_Q5b", "case": "In 2019, China's economic growth rate was 6.1% and Chinese households increased their spending. More Chinese people attended sports events and the earnings of top sportspeople increased. China exported more despite a rise in tariffs on some of its products. For example, the US imposed higher tariffs on the imports of Chinese tea and coffee.", "q": "Explain two reasons why some top sportspeople have high earnings.", "ans": [[["High demand / inelastic demand", "large crowds / TV fees / sponsorship / high gate receipts"], ["Low supply / inelastic supply", "skilled / talented / years of training / lack of substitutes"]], [["High demand / inelastic demand", "large crowds / TV fees / sponsorship / high gate receipts"], ["Low supply / inelastic supply", "skilled / talented / years of training / lack of substitutes"]]], "concept": "0455 s23 Q5(b). MS: demand (2) + supply (2)." },
  // --- S24 ---
  { "id": "SBb_PP_s24_Q2b", "case": "In 2020, wages paid to Mexican workers, including those in the primary sector, fell. This contributed to a 9% rise in poverty. In the same year, many small and medium-sized firms closed down. The country also suffered from traffic congestion. Mexico City is the world's most congested city.", "q": "Explain two policy measures which may reduce poverty.", "ans": [[["Minimum wage / introduce minimum wage", "raise income of low-paid workers / help low-paid workers"], ["State benefits / unemployment benefit", "enable unemployed to buy necessities / basic necessities"], ["Reduce indirect taxation", "tax falls heavily on poor / tax on goods and services"], ["Education / training", "increase earning potential / employment opportunities / income"], ["Progressive taxes", "reduce relative poverty"], ["Job creation schemes / public sector jobs", "increase employment / raise incomes / expand state-owned firms"], ["Reduction in interest rate / expansionary monetary policy", "encourage firms to expand / take on more workers"], ["Increase in government spending", "increase employment opportunities"], ["Reduce direct taxation / expansionary fiscal policy", "encourage firms to expand / increase disposable income of poor"], ["Provide job information", "reduce frictional unemployment"], ["Introduce a maximum price", "make necessities affordable / essentials affordable"]], [["Minimum wage / introduce minimum wage", "raise income of low-paid workers / help low-paid workers"], ["State benefits / unemployment benefit", "enable unemployed to buy necessities / basic necessities"], ["Reduce indirect taxation", "tax falls heavily on poor / tax on goods and services"], ["Education / training", "increase earning potential / employment opportunities / income"], ["Progressive taxes", "reduce relative poverty"], ["Job creation schemes / public sector jobs", "increase employment / raise incomes / expand state-owned firms"], ["Reduction in interest rate / expansionary monetary policy", "encourage firms to expand / take on more workers"], ["Increase in government spending", "increase employment opportunities"], ["Reduce direct taxation / expansionary fiscal policy", "encourage firms to expand / increase disposable income of poor"], ["Provide job information", "reduce frictional unemployment"], ["Introduce a maximum price", "make necessities affordable / essentials affordable"]]], "concept": "0455 s24 Q2(b). MS verbatim: any two policy measures + explanation. 2281_s24_ms_22." },
  { "id": "SBb_PP_s24_Q3b", "case": "South America has millions of microeconomic decision-makers. During a pandemic, schools stayed closed longer than anywhere else. As a result, students received less education. The World Bank estimated that the average student would earn $24,000 less over their lifetime. In 2020, South America had an inflation rate of 6.3% and an economic growth rate of only 1.8%.", "q": "Explain how less education can reduce a person's lifetime earnings.", "ans": [[["May reduce qualifications", "lower mobility / reduce employment chance / more unemployment / lack information on job vacancies / primary sector / manual work"]], [["May reduce skills / adult literacy", "lower productivity / reduce promotion chance / less bargaining power / easier to replace / lower demand for them"]]], "concept": "0455 s24 Q3(b). MS verbatim 2281_s24_ms_22: qualifications (2) + skills/productivity (2)." },
  { "id": "SBb_PP_s24_Q4b", "case": "Tajikistan is one of Asia's low-income countries. Its currency, the somoni, has the key characteristics of money. More than one million Tajik people work abroad, mostly in Russia. In 2020, the Tajik government was concerned that the economy might experience a recession which could cause a fall in tax revenue. Despite this possibility, some Tajik firms bought new capital equipment.", "q": "Explain two characteristics of money.", "ans": [[["Generally acceptable", "people willing to accept as payment"], ["Portable", "easy to carry"], ["Durable", "will last / can be saved"], ["Limited in supply", "maintains value"]], [["Generally acceptable", "people willing to accept as payment"], ["Portable", "easy to carry"], ["Durable", "will last / can be saved"], ["Limited in supply", "maintains value"]]], "concept": "0455 s24 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_s24_Q5b", "case": "Free goods and economic goods are consumed in Poland. In 2020, demand for both economic goods and factors of production increased in Poland. For example, Polish consumers demanded more football shirts and the Polish government increased its spending on housing.", "q": "Explain two influences on demand for factors of production.", "ans": [[["Demand for the product", "derived demand / rise in product demand increases factor demand"], ["Price of the factor", "lower price increases demand"], ["Price of substitute factors", "e.g. more labour if capital price rises"], ["Productivity", "higher productivity increases demand"]], [["Demand for the product", "derived demand / rise in product demand increases factor demand"], ["Price of the factor", "lower price increases demand"], ["Price of substitute factors", "e.g. more labour if capital price rises"], ["Productivity", "higher productivity increases demand"]]], "concept": "0455 s24 Q5(b). MS: any two + explanation." },
  // --- S25 ---
  { "id": "SBb_PP_s25_Q2b", "case": "The world's four largest accountancy firms experienced a decline in demand for their services at the start of 2023. One cause was a decline in mergers in other industries. Three of the firms reduced the number of new workers they hired and the other announced job losses. The ability of workers to gain new jobs is influenced by their mobility.", "q": "Explain two disadvantages workers may experience as a result of losing their jobs.", "ans": [[["Loss of income", "lower living standards / poverty / inability to buy necessities"], ["Loss of skills", "need new skills / difficult to get another job"], ["Mental health / stress", "loss of self-esteem / harder to find work"], ["Harder to get a loan", "banks less confident of repayment"]], [["Loss of income", "lower living standards / poverty / inability to buy necessities"], ["Loss of skills", "need new skills / difficult to get another job"], ["Mental health / stress", "loss of self-esteem / harder to find work"], ["Harder to get a loan", "banks less confident of repayment"]]], "concept": "0455 s25 Q2(b). MS: any two + explanation." },
  { "id": "SBb_PP_s25_Q3b", "case": "In 2022, Paraguay's production possibility curve (PPC) shifted to the right. Paraguay has a mixed economic system. Its government provides merit goods and public goods. The country's private sector is a major producer of shampoo. The firms in the shampoo industry make use of division of labour. The number of firms in the industry is declining.", "q": "Explain, with an example of each, the difference between a merit good and a public good.", "ans": [[["Merit good: under-consumed / has external benefits", "e.g. education / healthcare"]], [["Public good: non-excludable / non-rival", "e.g. street lighting / defence"]]], "concept": "0455 s25 Q3(b). MS: merit (1+1) + public (1+1)." },
  { "id": "SBb_PP_s25_Q4b", "case": "In 2022, more than a quarter of a million workers, including doctors, left Sri Lanka to work in other countries. This was largely due to economic problems, including an inflation rate of 50%. The Sri Lankan Government increased direct taxation. It also encouraged some public sector workers to work abroad temporarily. People who work abroad often send money home to relatives.", "q": "Explain two ways that money received from relatives working abroad could raise their families' living standards.", "ans": [[["Spend more on food / products", "reduce poverty / higher purchasing power"], ["Spend on education", "increase earning potential"], ["Spend on healthcare", "raise life expectancy"], ["Spend on housing", "reduce illness"]], [["Spend more on food / products", "reduce poverty / higher purchasing power"], ["Spend on education", "increase earning potential"], ["Spend on healthcare", "raise life expectancy"], ["Spend on housing", "reduce illness"]]], "concept": "0455 s25 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_s25_Q5b", "case": "In 2023, the Chinese Government aimed for 5% economic growth. It was expected that higher output would be caused mainly by an increase in household spending. Another aim was to keep the unemployment rate at around 5.5%. China has an ageing population and an ageing labour force.", "q": "Explain two advantages of employing older workers.", "ans": [[["More experienced", "high productivity / high skills"], ["Make few mistakes", "high quality products"], ["Reliable / easy to manage", "punctual / carry out duties carefully"], ["Need little training", "keep costs low"], ["Train young workers", "pass on experience"]], [["More experienced", "high productivity / high skills"], ["Make few mistakes", "high quality products"], ["Reliable / easy to manage", "punctual / carry out duties carefully"], ["Need little training", "keep costs low"], ["Train young workers", "pass on experience"]]], "concept": "0455 s25 Q5(b). MS: any two + explanation." },
  // --- M21 ---
  { "id": "SBb_PP_m21_Q2b", "case": "India has experienced a relatively high economic growth rate. This growth has been driven by increases in government spending and exports, including exports of textiles. India's unemployment rate has, however, increased. The government is concerned that trying to reduce unemployment may increase India's inflation rate.", "q": "Explain the possible opportunity cost to India of exporting more textiles.", "ans": [[["Opportunity cost is next best alternative forgone", "textiles exported could have been sold at home"]], [["Resources used for textile exports", "could have produced other products / lost revenue from other exports"]]], "concept": "0455 m21 Q2(b). MS: definition (2) + application (2)." },
  { "id": "SBb_PP_m21_Q3b", "case": "In the Netherlands in 2018, there were 1.3 bicycles per person. Land is scarce in city centres, where most cycling takes place. Demand for bikes in the Netherlands is price-inelastic. Only a few people in the Netherlands borrow money to buy bikes.", "q": "Explain two reasons why demand for a product may be price-inelastic.", "ans": [[["Lack of close substitutes", "not able to switch if price rises"], ["Necessity", "difficult to do without"], ["Small part of income", "price change not significant"], ["Addictive", "difficult to stop consuming"]], [["Lack of close substitutes", "not able to switch if price rises"], ["Necessity", "difficult to do without"], ["Small part of income", "price change not significant"], ["Addictive", "difficult to stop consuming"]]], "concept": "0455 m21 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_m21_Q4b", "case": "It is estimated that half of Egyptian men smoke. This is one of the highest rates in the world. In recent years the Egyptian government has increased the tax on cigarettes. The government and central bank have also tried to reduce inflation and improve Egypt's international trade performance.", "q": "Explain two reasons why governments tax cigarettes.", "ans": [[["To raise revenue", "demand inelastic / addictive"], ["To discourage consumption", "demerit good / health problems"], ["To reduce external costs", "impose cost on third parties / passive smoking"]], [["To raise revenue", "demand inelastic / addictive"], ["To discourage consumption", "demerit good / health problems"], ["To reduce external costs", "impose cost on third parties / passive smoking"]]], "concept": "0455 m21 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_m21_Q5b", "case": "Sweden has a mixed economic system. In 2018, it was operating at a point inside its production possibility curve. In 2018, the country's schools employed nearly 2500 extra teachers. A few of these had previously been actors. A higher number had previously been government officials involved with regulation of Swedish monopolies.", "q": "Explain the difference between a point inside a PPC and a point outside a PPC.", "ans": [[["Point inside: unemployed resources", "inefficient / output below potential / attainable"]], [["Point outside: unattainable", "not enough resources / beyond productive potential / only with economic growth"]]], "concept": "0455 m21 Q5(b). MS: inside (2) + outside (2)." },
  // --- M22 ---
  { "id": "SBb_PP_m22_Q2b", "case": "South Africa experienced a recession in the second half of 2019 and an unemployment rate of 29%. Only a small proportion of this unemployment was frictional. South Africa's foreign exchange rate fell from 1 rand = US$0.08 in 2018 to 1 rand = US$0.06 in 2019. South Africa had reduced import tariffs, but in 2019 some economists suggested tariffs should be used to protect infant industries.", "q": "Explain why an infant industry may need protection.", "ans": [[["New industries need time to grow", "competing with established foreign firms / economies of scale"]], [["Foreign firms may have lower costs", "may drive infant industry out of business / growth may increase employment"]]], "concept": "0455 m22 Q2(b). MS: need time (2) + competition (2)." },
  { "id": "SBb_PP_m22_Q3b", "case": "New Zealand is a small country with a population of 5 million. Most New Zealand firms are relatively small and most do not experience diseconomies of scale. New Zealand was the first country to introduce a national minimum wage. New Zealand experienced a rise in income per head every year between 2010 and 2019. During this period, 6% of New Zealand's households experienced absolute poverty.", "q": "Explain two reasons why a high-income household may borrow more than a low-income household.", "ans": [[["Banks more willing to lend", "more confident of repayment"], ["Banks may charge lower interest", "high-income borrow larger amount"], ["More confident of repaying", "expect income to rise / job security"], ["Significant wealth / assets", "able to offer collateral"]], [["Banks more willing to lend", "more confident of repayment"], ["Banks may charge lower interest", "high-income borrow larger amount"], ["More confident of repaying", "expect income to rise / job security"], ["Significant wealth / assets", "able to offer collateral"]]], "concept": "0455 m22 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_m22_Q4b", "case": "Botswana's net migration varies. In 2019, Botswana had net immigration. Since 2010, its unemployment rate has averaged 18%. Between 2010 and 2019, the number of women in the labour force increased from 380,000 to 490,000. Although Botswana is one of Africa's richer countries, its households do not save much of their income.", "q": "Explain two consequences of unemployment.", "ans": [[["Lower output / GDP", "inefficient use of resources / lower exports"], ["Lower income", "poverty / fall in living standards"], ["Lower tax revenue", "reduction in government spending"], ["Increased spending on benefits", "opportunity cost for healthcare etc"]], [["Lower output / GDP", "inefficient use of resources / lower exports"], ["Lower income", "poverty / fall in living standards"], ["Lower tax revenue", "reduction in government spending"], ["Increased spending on benefits", "opportunity cost for healthcare etc"]]], "concept": "0455 m22 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_m22_Q5b", "case": "The economic problem means that countries have to decide what to produce. Ghana uses much of its agricultural land to grow cocoa. Cocoa is sold to chocolate producers. The world's main chocolate producer in 2019 was a US firm with a 14% share of the global market. That firm was the largest seller of chocolate in the US and, if it merges, may become a monopoly.", "q": "Explain whether land is mobile.", "ans": [[["Most land geographically immobile", "fixed in one place / cannot move"]], [["Land occupationally mobile", "capable of changing use / e.g. farming or housing"]]], "concept": "0455 m22 Q5(b). MS: immobile (2) + mobile (2)." },
  // --- M23 ---
  { "id": "SBb_PP_m23_Q2b", "case": "Vietnam has a high number of female entrepreneurs. Some firms compete with foreign MNCs and public sector firms. The Vietnamese government encourages MNCs to locate in Vietnam. It also intervenes in the economy to encourage the consumption of merit goods.", "q": "Explain two benefits that an MNC can bring to its host country.", "ans": [[["Increase employment", "raise living standards / reduce poverty"], ["Increase skills", "provide training to workers"], ["Increase exports", "improve current account"], ["Bring new technology", "raise productivity / quality"]], [["Increase employment", "raise living standards / reduce poverty"], ["Increase skills", "provide training to workers"], ["Increase exports", "improve current account"], ["Bring new technology", "raise productivity / quality"]]], "concept": "0455 m23 Q2(b). MS: any two + explanation." },
  { "id": "SBb_PP_m23_Q3b", "case": "In 2019, India became the world's largest producer of sugar. Sugar cane is grown by a large number of mainly low-income farmers. They sell sugar cane to mills which process it into sugar. Processing is more capital-intensive than growing. The Indian government sets a minimum price for sugar cane and subsidises the export of sugar.", "q": "Explain two advantages of capital-intensive production.", "ans": [[["Lower costs of production", "large scale / lower prices / higher profits"], ["Raise productivity / efficiency", "higher output / produce faster"], ["Quality / consistency", "may increase demand"]], [["Lower costs of production", "large scale / lower prices / higher profits"], ["Raise productivity / efficiency", "higher output / produce faster"], ["Quality / consistency", "may increase demand"]]], "concept": "0455 m23 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_m23_Q4b", "case": "By 2020, 40% of Turkish doctors were women. Over this period, labour productivity increased. Turkey experienced advances in technology and a change in the current account balance. Turkey also had a significant increase in the size of its population.", "q": "Explain two reasons why someone may choose to become a doctor.", "ans": [[["High pay", "high living standards / low supply / high demand"], ["Vocation", "wanting to help people"], ["Job satisfaction", "enjoying the challenges"], ["Job security", "difficult to replace / essential service"]], [["High pay", "high living standards / low supply / high demand"], ["Vocation", "wanting to help people"], ["Job satisfaction", "enjoying the challenges"], ["Job security", "difficult to replace / essential service"]]], "concept": "0455 m23 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_m23_Q5b", "case": "Serbia is the world's second largest producer of raspberries, a product with elastic demand. Consumers experience the economic problem when buying raspberries. Few raspberry farm workers are members of trade unions. Membership of trade unions in Serbia had fallen to 20% of all workers by 2020. In that year, Serbia had more state pensioners than workers.", "q": "Explain how the economic problem results in consumers having to make choices.", "ans": [[["Economic problem: unlimited wants", "exceeding limited resources / scarcity"]], [["Consumers have limited incomes", "cannot buy everything / buying one product involves opportunity cost"]]], "concept": "0455 m23 Q5(b). MS: problem (2) + choices (2)." },
  // --- M24 ---
  { "id": "SBb_PP_m24_Q2b", "case": "Since 2016, South Korea's population has declined, due to a falling birth rate. A high proportion of its population is now aged over 64. The South Korean government has used tax revenue to give cash incentives to couples to have more children. However, many parents have chosen to have fewer children and spend more on each child to ensure they get a good education.", "q": "Explain two reasons for a change in the amount of tax revenue a government receives.", "ans": [[["Change in GDP / economic growth", "affect direct taxes / tax brackets"], ["Change in employment / wages", "affect income tax"], ["Change in profits", "affect corporation tax"], ["Change in spending", "affect indirect taxes / VAT"]], [["Change in GDP / economic growth", "affect direct taxes / tax brackets"], ["Change in employment / wages", "affect income tax"], ["Change in profits", "affect corporation tax"], ["Change in spending", "affect indirect taxes / VAT"]]], "concept": "0455 m24 Q2(b). MS: any two + explanation." },
  { "id": "SBb_PP_m24_Q3b", "case": "Some firms in Monaco have experienced external growth. Firms in Monaco pay high wages. Workers in Monaco benefit from fiscal policy which contributes to high employment. Their government does impose VAT on food, including fruit.", "q": "Explain two reasons why low-skilled workers may be highly paid.", "ans": [[["High demand / inelastic demand", "expansion of industry / economy"], ["Low supply", "emigration / high employment"], ["Minimum wage", "set at high level"], ["Dangerous / unpleasant job", "high wage needed to attract workers"], ["Trade union", "strong bargaining power"]], [["High demand / inelastic demand", "expansion of industry / economy"], ["Low supply", "emigration / high employment"], ["Minimum wage", "set at high level"], ["Dangerous / unpleasant job", "high wage needed to attract workers"], ["Trade union", "strong bargaining power"]]], "concept": "0455 m24 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_m24_Q4b", "case": "In 2021, the Suez Canal was blocked by one of the world's biggest container ships. This affected some firms' profits and caused a shortage in a number of products. The delivery of luxury chocolate and salt was delayed. These two goods have differences in their price elasticity of demand.", "q": "Explain two ways a firm can increase its profit.", "ans": [[["Become more capital-intensive", "reduce cost of production"], ["Buy cheaper raw materials", "reduce costs"], ["Increase efficiency / quality", "employ skilled workers"], ["Merging", "economies of scale"], ["Advertising", "increase demand / revenue"]], [["Become more capital-intensive", "reduce cost of production"], ["Buy cheaper raw materials", "reduce costs"], ["Increase efficiency / quality", "employ skilled workers"], ["Merging", "economies of scale"], ["Advertising", "increase demand / revenue"]]], "concept": "0455 m24 Q4(b). MS: any two + explanation." },
  { "id": "SBb_PP_m24_Q5b", "case": "New Zealand is a high-income country with a low unemployment rate and a surplus of imports over exports. In 2022, it banned everyone born after 2008 from buying cigarettes. A year before, it gave permission for firms to explore for oil in the country.", "q": "Explain two reasons why a government may discourage cigarette smoking.", "ans": [[["Improve health", "smoking harms health / demerit good"], ["Reduce passive smoking", "health damage to non-smokers"], ["Reduce healthcare costs", "more for education etc"], ["Reduce market failure", "reduce external costs"]], [["Improve health", "smoking harms health / demerit good"], ["Reduce passive smoking", "health damage to non-smokers"], ["Reduce healthcare costs", "more for education etc"], ["Reduce market failure", "reduce external costs"]]], "concept": "0455 m24 Q5(b). MS: any two + explanation." },
  // --- M25 ---
  { "id": "SBb_PP_m25_Q2b", "case": "South Korea makes use of both economic goods and free goods. Its output includes products with both elastic and inelastic supply. The country is building the world's first floating city, estimated to cost $180m, to cope with rising sea levels caused by climate change. Governments take measures to reduce greenhouse gases, including banning the burning of wood to heat homes.", "q": "Explain how opportunity cost will influence a government's decision on whether to spend tax revenue on a large infrastructure project.", "ans": [[["Opportunity cost is next best alternative forgone", "tax revenue is limited"]], [["Spending on project means cannot spend elsewhere", "government must consider priorities / which spending gives greatest benefit"]]], "concept": "0455 m25 Q2(b). MS: definition (2) + influence (2)." },
  { "id": "SBb_PP_m25_Q3b", "case": "Estonia's factors of production are employed in education, building and clothing. In 2022, the country experienced a shortage of teachers. The government increased teachers' wages to attract workers from other industries. Estonia's clothing industry has firms of different sizes. Estonia's firms were affected in 2022 by the government increasing the money supply.", "q": "Explain two reasons why building workers may not become teachers.", "ans": [[["May lack skills", "occupationally immobile"], ["May lack qualifications", "insufficient education / training"], ["May be paid more as builders", "physically demanding / dangerous job"], ["Geographically immobile", "unable to move to teaching jobs"]], [["May lack skills", "occupationally immobile"], ["May lack qualifications", "insufficient education / training"], ["May be paid more as builders", "physically demanding / dangerous job"], ["Geographically immobile", "unable to move to teaching jobs"]]], "concept": "0455 m25 Q3(b). MS: any two + explanation." },
  { "id": "SBb_PP_m25_Q4b", "case": "Nigeria has a mixed economic system. In January 2023, Nigeria had a high unemployment rate of 33% which created a number of costs. Its high inflation rate of 22% had several effects on the country's firms. In 2022 and the start of 2023, Nigerians increased their demand for foreign currency.", "q": "Explain how the key resource allocation decisions are made in a mixed economic system.", "ans": [[["Private sector uses price mechanism", "demand and supply / profit motive / cost-effective methods"]], [["Public sector uses spending / taxation / regulation", "influenced by social costs and benefits"]]], "concept": "0455 m25 Q4(b). MS: private (2) + public (2). Max 3 if only one sector." },
  { "id": "SBb_PP_m25_Q5b", "case": "Finland is a high-income country that usually has a higher value of exports than imports. It has a strong commercial banking sector which has increased its lending in recent years. The country has an ageing population, with more than a quarter aged over 65. In 2022, Finland's Government had a budget deficit with government spending exceeding tax revenue.", "q": "Explain why commercial banks may increase their lending.", "ans": [[["To increase profits", "earn more interest / high interest rates"], ["Increase in demand for loans", "low interest rates / optimism"], ["Increased confidence loans repaid", "rise in incomes"], ["Increase in deposits", "more money to lend"]], [["To increase profits", "earn more interest / high interest rates"], ["Increase in demand for loans", "low interest rates / optimism"], ["Increased confidence loans repaid", "rise in incomes"], ["Increase in deposits", "more money to lend"]]], "concept": "0455 m25 Q5(b). MS: any two + explanation." },

  // ═══════════════════════════════════════════════════════════════
  // SYLLABUS 1: The basic economic problem
  // ═══════════════════════════════════════════════════════════════
  { "id": "SBb_s1_PPC_growth", "case": "Chile's production possibility curve shifted to the right between 2018 and 2022. Investment in copper mining and technology increased. The quality of the labour force improved.", "q": "Explain two causes of an outward shift in a country's production possibility curve.", "ans": [[["Increase in quantity or quality of factors of production", "more resources / better trained workers / more capital"], ["Improvement in technology", "more output from same inputs / higher productivity"], ["Increase in investment", "adds to capital stock / raises productive capacity"]], [["Increase in quantity or quality of factors of production", "more resources / better trained workers / more capital"], ["Improvement in technology", "more output from same inputs / higher productivity"], ["Increase in investment", "adds to capital stock / raises productive capacity"]]], "concept": "Syllabus 1.4.4. PPC shifts: factors, technology, investment." },
  { "id": "SBb_s1_opportunity_cost", "case": "Kenya must choose between producing tea for export and growing food for domestic consumption. The government is considering using more land for commercial farming.", "q": "Explain two possible opportunity costs of a government using more land for commercial farming.", "ans": [[["Less land for food production", "may reduce domestic food supply / could increase food imports"]], [["Less land for housing or industry", "may restrict other sectors / affect urban development"]]], "concept": "Syllabus 1.3.1. Opportunity cost of resource use." },

  // ═══════════════════════════════════════════════════════════════
  // SYLLABUS 2: The allocation of resources
  // ═══════════════════════════════════════════════════════════════
  { "id": "SBb_s2_demand_shift", "case": "Demand for electric cars in Norway increased when the government offered subsidies and fuel prices rose. Sales of petrol cars fell.", "q": "Explain two causes of an increase in demand for a product.", "ans": [[["Rise in income", "normal good - consumers buy more at each price / higher purchasing power"], ["Rise in price of substitute", "e.g. petrol cars - electric becomes relatively cheaper"], ["Change in tastes and preferences", "consumers prefer the product / advertising"], ["Government policy / subsidies", "lowers effective price / makes product more attractive"]], [["Rise in income", "normal good - consumers buy more at each price / higher purchasing power"], ["Rise in price of substitute", "e.g. petrol cars - electric becomes relatively cheaper"], ["Change in tastes and preferences", "consumers prefer the product / advertising"], ["Government policy / subsidies", "lowers effective price / makes product more attractive"]]], "concept": "Syllabus 2.3.4. Conditions of demand." },
  { "id": "SBb_s2_supply_shift", "case": "Wheat supply in Ukraine fell in 2022. The price of fertiliser rose. Some farmland was damaged.", "q": "Explain two causes of a decrease in supply of a product.", "ans": [[["Rise in costs of production", "e.g. fertiliser / wages - producers supply less at each price"], ["Decrease in number of producers", "firms leave the market / reduces market supply"], ["Adverse weather / natural factors", "reduces output / crop failure"], ["Higher price of alternative product", "producers switch to producing other goods"]], [["Rise in costs of production", "e.g. fertiliser / wages - producers supply less at each price"], ["Decrease in number of producers", "firms leave the market / reduces market supply"], ["Adverse weather / natural factors", "reduces output / crop failure"], ["Higher price of alternative product", "producers switch to producing other goods"]]], "concept": "Syllabus 2.4.4. Conditions of supply." },
  { "id": "SBb_s2_PED_revenue", "case": "A bus company raised ticket prices. Revenue fell. Demand for bus travel is sensitive to price changes.", "q": "Explain two factors that may make demand for a product price-elastic.", "ans": [[["Many close substitutes", "consumers switch to alternatives if price rises"], ["Luxury / non-necessity", "not essential - consumers cut back when price rises"], ["Large proportion of income", "price rise has significant effect on purchasing power"], ["Time to adjust", "in the long run consumers find alternatives"]], [["Many close substitutes", "consumers switch to alternatives if price rises"], ["Luxury / non-necessity", "not essential - consumers cut back when price rises"], ["Large proportion of income", "price rise has significant effect on purchasing power"], ["Time to adjust", "in the long run consumers find alternatives"]]], "concept": "Syllabus 2.7.3. Determinants of PED." },
  { "id": "SBb_s2_minimum_price", "case": "The EU sets a minimum price for agricultural products such as sugar. The aim is to support farmers' incomes.", "q": "Explain two reasons why a government may set a minimum price.", "ans": [[["Protect producer incomes", "ensure farmers earn enough / prevent prices falling too low"], ["Encourage production", "incentive to produce more / maintain supply of essential goods"], ["Support an industry", "protect jobs / prevent industry decline"]], [["Protect producer incomes", "ensure farmers earn enough / prevent prices falling too low"], ["Encourage production", "incentive to produce more / maintain supply of essential goods"], ["Support an industry", "protect jobs / prevent industry decline"]]], "concept": "Syllabus 2.11.2. Minimum price - price floor." },
  { "id": "SBb_s2_maximum_price", "case": "The Venezuelan government set a maximum price for basic food staples during high inflation. Sellers could not legally charge above this level. The aim was to make bread and rice affordable for low-income families.", "q": "Explain two reasons why a government may set a maximum price.", "ans": [[["Make essential goods affordable / reduce poverty", "protect low-income consumers / ensure access to basic necessities"], ["Control inflation", "prevent firms charging excessive prices / limit price rises"]], [["Make essential goods affordable / reduce poverty", "protect low-income consumers / ensure access to basic necessities"], ["Control inflation", "prevent firms charging excessive prices / limit price rises"]]], "concept": "Syllabus 2.11.2. Maximum price - price ceiling." },
  { "id": "SBb_s2_PES", "case": "A coal mine in Australia takes years to develop. Coal can be stored but storage is costly. When world coal demand rose, Australian producers could not quickly increase supply.", "q": "Explain two factors that may make the supply of a product price-inelastic.", "ans": [[["Long production time", "takes time to increase output / cannot respond quickly to price rise"], ["Limited spare capacity", "firms already producing near maximum / cannot expand quickly"], ["Perishable / hard to store", "cannot stockpile to release when price rises"], ["Few factors mobile", "resources cannot easily switch into this production"]], [["Long production time", "takes time to increase output / cannot respond quickly to price rise"], ["Limited spare capacity", "firms already producing near maximum / cannot expand quickly"], ["Perishable / hard to store", "cannot stockpile to release when price rises"], ["Few factors mobile", "resources cannot easily switch into this production"]]], "concept": "Syllabus 2.8.3. Determinants of PES." },
  { "id": "SBb_s2_market_intervention", "case": "The Tunisian government regulates the price of flour and milk. It also subsidises electricity. Government control aims to reduce poverty and prevent monopoly firms exploiting their market power.", "q": "Explain two reasons why a government may intervene in a market.", "ans": [[["Reduce poverty / make essentials affordable", "protect low-income consumers / ensure access to basic goods"], ["Correct market failure", "externalities / public goods / monopoly exploitation - market fails to allocate efficiently"], ["Prevent monopoly abuse", "stop firms charging excessive prices / protect consumers"]], [["Reduce poverty / make essentials affordable", "protect low-income consumers / ensure access to basic goods"], ["Correct market failure", "externalities / public goods / monopoly exploitation - market fails to allocate efficiently"], ["Prevent monopoly abuse", "stop firms charging excessive prices / protect consumers"]]], "concept": "Syllabus 2.10–2.11. Government intervention." },

  // ═══════════════════════════════════════════════════════════════
  // SYLLABUS 3: Microeconomic decision makers
  // ═══════════════════════════════════════════════════════════════
  { "id": "SBb_s3_division_labour", "case": "A car factory in Mexico uses division of labour. Each worker on the assembly line performs one specific task. Output per worker has increased.", "q": "Explain two advantages of division of labour for a firm.", "ans": [[["Higher productivity / efficiency", "workers specialise / become faster at their task / practice makes perfect"], ["Lower costs of production", "less training per worker / less time switching tasks / economies of scale"], ["Better quality", "workers skilled in one task / fewer mistakes"]], [["Higher productivity / efficiency", "workers specialise / become faster at their task / practice makes perfect"], ["Lower costs of production", "less training per worker / less time switching tasks / economies of scale"], ["Better quality", "workers skilled in one task / fewer mistakes"]]], "concept": "Syllabus 3.3.4. Division of labour." },
  { "id": "SBb_s3_trade_union", "case": "Workers at a factory in Poland joined a trade union. The union negotiated for higher wages and better conditions. The employer agreed to pay rises.", "q": "Explain two benefits of trade union membership for workers.", "ans": [[["Collective bargaining", "more power than individual / negotiate better pay and conditions"], ["Protection from unfair treatment", "legal support / representation in disputes"], ["Job security", "negotiate redundancy terms / protect employment"]], [["Collective bargaining", "more power than individual / negotiate better pay and conditions"], ["Protection from unfair treatment", "legal support / representation in disputes"], ["Job security", "negotiate redundancy terms / protect employment"]]], "concept": "Syllabus 3.4.1. Trade unions." },
  { "id": "SBb_s3_economies_scale", "case": "A large supermarket chain has lower average cost per unit than smaller rivals. It buys in bulk and spreads fixed costs over more output.", "q": "Explain two types of internal economies of scale.", "ans": [[["Technical economies", "large machines used fully / specialised equipment / division of labour"], ["Purchasing / buying economies", "bulk buying / discounts from suppliers / lower cost per unit"], ["Financial economies", "easier to borrow / lower interest rates / cheaper finance"], ["Managerial economies", "specialist managers / more efficient organisation"]], [["Technical economies", "large machines used fully / specialised equipment / division of labour"], ["Purchasing / buying economies", "bulk buying / discounts from suppliers / lower cost per unit"], ["Financial economies", "easier to borrow / lower interest rates / cheaper finance"], ["Managerial economies", "specialist managers / more efficient organisation"]]], "concept": "Syllabus 3.5.5. Internal economies of scale." },
  { "id": "SBb_s3_productivity", "case": "A factory in South Korea installed new machinery. Output per worker increased by 20%. The firm also invested in training.", "q": "Explain two causes of an increase in labour productivity.", "ans": [[["Better technology / more capital", "workers have better tools / machinery increases output per worker"], ["Training / education", "workers more skilled / make fewer mistakes / work faster"], ["Division of labour", "specialisation raises efficiency"], ["Better working conditions", "may increase motivation / reduce absenteeism"]], [["Better technology / more capital", "workers have better tools / machinery increases output per worker"], ["Training / education", "workers more skilled / make fewer mistakes / work faster"], ["Division of labour", "specialisation raises efficiency"], ["Better working conditions", "may increase motivation / reduce absenteeism"]]], "concept": "Syllabus 3.6.3. Production and productivity." },
  { "id": "SBb_s3_monopoly_disadvantages", "case": "The national water company in Uruguay is the only supplier of piped water to households. There are no competitors. Consumers complain about high prices and poor service.", "q": "Explain two disadvantages of a monopoly for consumers.", "ans": [[["Higher prices", "no competition / monopoly can charge more than competitive market"], ["Lack of choice", "no alternative supplier / one product only"], ["Poor quality / service", "no incentive to improve / consumers have no alternative"]], [["Higher prices", "no competition / monopoly can charge more than competitive market"], ["Lack of choice", "no alternative supplier / one product only"], ["Poor quality / service", "no incentive to improve / consumers have no alternative"]]], "concept": "Syllabus 3.8.2. Monopoly disadvantages." },
  { "id": "SBb_s3_merger_benefits", "case": "Two Thai commercial banks merged in 2020. The merged bank was expected to charge lower prices for some services and offer better quality. The merger created one of the largest banks in the country.", "q": "Explain two advantages a firm may gain from merging with another firm.", "ans": [[["Economies of scale", "lower average cost / reducing costs / reduce costs / bulk buying / spread fixed costs / higher efficiency / merging operations"], ["Increased market share / power / monopoly / less competition", "more customers / stronger position / charge higher prices / charge more / charge better"], ["Diversification", "spread risk / enter new markets / more stable profits"]], [["Economies of scale", "lower average cost / reducing costs / reduce costs / bulk buying / spread fixed costs / higher efficiency / merging operations"], ["Increased market share / power / monopoly / less competition", "more customers / stronger position / charge higher prices / charge more / charge better"], ["Diversification", "spread risk / enter new markets / more stable profits"]]], "concept": "Syllabus 3.5.4. Merger benefits. MS: credit same meaning." },

  // ═══════════════════════════════════════════════════════════════
  // SYLLABUS 4: Government and the macroeconomy
  // ═══════════════════════════════════════════════════════════════
  { "id": "SBb_s4_inflation_causes", "case": "Turkey's inflation rate reached 65% in 2023. Consumer spending increased sharply. The cost of imported energy and raw materials rose. Wage increases were negotiated by trade unions.", "q": "Explain two causes of inflation.", "ans": [[["Demand-pull inflation", "total demand exceeds supply / excess demand / consumers and firms spending more"]], [["Cost-push inflation", "rise in costs of production / higher wages / higher import prices / raw material costs"]]], "concept": "Syllabus 4.8.3. Demand-pull and cost-push." },
  { "id": "SBb_s4_fiscal_aims", "case": "The UK government raised income tax and cut spending in 2023. The aim was to reduce the budget deficit and control inflation.", "q": "Explain two ways fiscal policy could be used to reduce inflation.", "ans": [[["Raise taxation", "reduce disposable income / lower consumer spending / reduce total demand"], ["Cut government spending", "reduce total demand / less money in circulation"], ["Reduce demand-pull inflation", "excess demand causes inflation / fiscal policy reduces demand"]], [["Raise taxation", "reduce disposable income / lower consumer spending / reduce total demand"], ["Cut government spending", "reduce total demand / less money in circulation"], ["Reduce demand-pull inflation", "excess demand causes inflation / fiscal policy reduces demand"]]], "concept": "Syllabus 4.3.7, 4.8.5. Fiscal policy." },
  { "id": "SBb_s4_monetary_aims", "case": "The European Central Bank raised interest rates in 2023 to bring inflation under control. Borrowing became more expensive.", "q": "Explain two ways a central bank could use monetary policy to reduce inflation.", "ans": [[["Raise interest rates", "cost of borrowing increases / discourages spending and investment / reduces total demand"], ["Reduce money supply", "open market operations - sell bonds / less money in circulation"], ["Reduce demand-pull inflation", "lower demand brings down prices"]], [["Raise interest rates", "cost of borrowing increases / discourages spending and investment / reduces total demand"], ["Reduce money supply", "open market operations - sell bonds / less money in circulation"], ["Reduce demand-pull inflation", "lower demand brings down prices"]]], "concept": "Syllabus 4.4.2. Monetary policy measures." },
  { "id": "SBb_s4_unemployment_policies", "case": "Portugal had high unemployment when car factories closed. Some workers had skills that no longer matched available jobs. The government introduced training schemes.", "q": "Explain two policies a government could use to reduce unemployment.", "ans": [[["Supply-side: education and training", "improve skills / reduce structural unemployment / workers match job vacancies"], ["Fiscal: increase government spending", "create jobs directly / boost demand / reduce cyclical unemployment"], ["Reduce unemployment benefit", "incentive to find work quickly / reduce frictional unemployment"], ["Cut taxes", "encourage firms to invest and hire / boost demand"]], [["Supply-side: education and training", "improve skills / reduce structural unemployment / workers match job vacancies"], ["Fiscal: increase government spending", "create jobs directly / boost demand / reduce cyclical unemployment"], ["Reduce unemployment benefit", "incentive to find work quickly / reduce frictional unemployment"], ["Cut taxes", "encourage firms to invest and hire / boost demand"]]], "concept": "Syllabus 4.7.6. Policies to reduce unemployment." },
  { "id": "SBb_s4_economic_growth", "case": "Vietnam's economy grew by 5% in 2023. Investment in new factories increased. The labour force expanded and productivity improved.", "q": "Explain two causes of economic growth.", "ans": [[["Increase in investment", "adds to capital stock / raises productive capacity / more output possible"], ["Increase in productivity", "same inputs produce more / technology / skills / efficiency"], ["Increase in quantity of factors of production", "more labour / more capital / more land used productively"]], [["Increase in investment", "adds to capital stock / raises productive capacity / more output possible"], ["Increase in productivity", "same inputs produce more / technology / skills / efficiency"], ["Increase in quantity of factors of production", "more labour / more capital / more land used productively"]]], "concept": "Syllabus 4.6.4. Causes of economic growth." },
  { "id": "SBb_s4_inflation_costs", "case": "Turkey's inflation rate reached 65% in 2023. Savers saw the value of their money fall. Firms were uncertain about future costs and delayed investment decisions.", "q": "Explain two costs of inflation to an economy.", "ans": [[["Reduces purchasing power of money", "savers lose / fixed incomes lose / real value of savings falls"], ["Creates uncertainty", "firms delay investment / harder to plan / reduces economic growth"], ["May reduce international competitiveness", "exports become dearer / lose export sales"], ["Menu costs", "firms must change prices frequently / administrative burden"]], [["Reduces purchasing power of money", "savers lose / fixed incomes lose / real value of savings falls"], ["Creates uncertainty", "firms delay investment / harder to plan / reduces economic growth"], ["May reduce international competitiveness", "exports become dearer / lose export sales"], ["Menu costs", "firms must change prices frequently / administrative burden"]]], "concept": "Syllabus 4.8.4. Costs of inflation." },
  { "id": "SBb_s4_supply_side", "case": "The Polish government invested in vocational training and reduced business regulations. It cut corporation tax to encourage firms to invest. The aim is to increase the economy's productive potential and reduce unemployment.", "q": "Explain two supply-side policy measures a government could use.", "ans": [[["Education and training", "improve skills / productivity / reduce structural unemployment / workers match vacancies"], ["Deregulation", "reduce rules / lower costs / encourage enterprise / easier to start firms"], ["Cut corporation tax", "firms retain more profit / encourage investment / add to capital stock"], ["Privatisation", "profit motive / efficiency / competition"]], [["Education and training", "improve skills / productivity / reduce structural unemployment / workers match vacancies"], ["Deregulation", "reduce rules / lower costs / encourage enterprise / easier to start firms"], ["Cut corporation tax", "firms retain more profit / encourage investment / add to capital stock"], ["Privatisation", "profit motive / efficiency / competition"]]], "concept": "Syllabus 4.5.2. Supply-side policy measures." },
  { "id": "SBb_s4_budget_deficit", "case": "Bhutan's government spending in 2018 was $450m while tax revenue was $380m. The government announced increased spending on health and education. The labour force is mostly in agriculture.", "q": "Explain two reasons why a government may run a budget deficit.", "ans": [[["Increase spending on priorities", "health education infrastructure / meet public needs / recession spending"], ["Low tax revenue / recession", "incomes and profits fall / tax intake falls when economy slows"], ["Counter cyclical policy", "boost demand during recession / stimulate economy"]], [["Increase spending on priorities", "health education infrastructure / meet public needs / recession spending"], ["Low tax revenue / recession", "incomes and profits fall / tax intake falls when economy slows"], ["Counter cyclical policy", "boost demand during recession / stimulate economy"]]], "concept": "Syllabus 4.3. Budget deficit reasons." },

  // ═══════════════════════════════════════════════════════════════
  // SYLLABUS 5: Economic development
  // ═══════════════════════════════════════════════════════════════
  { "id": "SBb_s5_HDI", "case": "Costa Rica scored well on the Human Development Index. It had high life expectancy, a high level of education and a reasonable GDP per head.", "q": "Explain two advantages of using the HDI rather than GDP per head to measure development.", "ans": [[["HDI includes non-income factors", "life expectancy and education - broader measure of wellbeing"], ["Reflects quality of life", "health and education matter for living standards / GDP only measures output"], ["More accurate for comparing living standards", "country may have high GDP but poor health/education"]], [["HDI includes non-income factors", "life expectancy and education - broader measure of wellbeing"], ["Reflects quality of life", "health and education matter for living standards / GDP only measures output"], ["More accurate for comparing living standards", "country may have high GDP but poor health/education"]]], "concept": "Syllabus 5.1.1. HDI vs GDP." },
  { "id": "SBb_s5_population", "case": "Ireland's population grew in the 2010s. The birth rate remained relatively high and there was net immigration. Both factors increased the size of the population.", "q": "Explain two effects of an increase in population size on an economy.", "ans": [[["May increase labour force", "more workers / potential for higher output / economic growth"], ["May increase demand", "more consumers / higher spending / boost firms' sales"], ["May increase pressure on resources", "more demand for housing / education / jobs / strain on infrastructure"], ["May reduce GDP per head", "if output does not rise proportionally"]], [["May increase labour force", "more workers / potential for higher output / economic growth"], ["May increase demand", "more consumers / higher spending / boost firms' sales"], ["May increase pressure on resources", "more demand for housing / education / jobs / strain on infrastructure"], ["May reduce GDP per head", "if output does not rise proportionally"]]], "concept": "Syllabus 5.3.3. Effects of population change." },
  { "id": "SBb_s5_poverty_policies", "case": "Brazil has high income inequality. The government uses progressive taxation and provides benefits to low-income families. Spending on education has increased.", "q": "Explain two policies a government could use to reduce poverty.", "ans": [[["Progressive taxation", "takes higher proportion from rich / revenue used for benefits / redistribution"], ["State benefits / welfare", "transfer payments to poor / unemployment benefit / child support"], ["Spending on education", "improve skills / higher future earnings / break poverty cycle"], ["Minimum wage", "ensure workers earn enough for basic needs"]], [["Progressive taxation", "takes higher proportion from rich / revenue used for benefits / redistribution"], ["State benefits / welfare", "transfer payments to poor / unemployment benefit / child support"], ["Spending on education", "improve skills / higher future earnings / break poverty cycle"], ["Minimum wage", "ensure workers earn enough for basic needs"]]], "concept": "Syllabus 5.2.3. Policies to alleviate poverty." },
  { "id": "SBb_s5_poverty_causes", "case": "Many people in rural Pakistan live in poverty. Unemployment is high and wages in agriculture are low. Illness and lack of education make it difficult for families to escape poverty.", "q": "Explain two causes of poverty.", "ans": [[["Unemployment / lack of jobs", "no income / cannot afford basic necessities / demand-deficient or structural"], ["Low wages", "earnings below poverty line / cannot afford food shelter clothing"], ["Illness / disability", "cannot work / medical costs / loss of income"], ["Lack of education / skills", "limited job opportunities / low-paid work only"]], [["Unemployment / lack of jobs", "no income / cannot afford basic necessities / demand-deficient or structural"], ["Low wages", "earnings below poverty line / cannot afford food shelter clothing"], ["Illness / disability", "cannot work / medical costs / loss of income"], ["Lack of education / skills", "limited job opportunities / low-paid work only"]]], "concept": "Syllabus 5.2.2. Causes of poverty." },
  { "id": "SBb_s5_economic_growth_development", "case": "Mauritius has grown since shifting from primary to tertiary sector. Growth increased income per head and improved healthcare. Life expectancy rose and infant mortality fell.", "q": "Explain two benefits of economic growth for living standards.", "ans": [[["Higher income per head", "people can afford more goods and services / better quality of life"], ["More tax revenue", "government can spend on health education infrastructure"], ["Improved healthcare", "life expectancy rises / infant mortality falls / people live longer"], ["More employment", "jobs created / incomes rise"]], [["Higher income per head", "people can afford more goods and services / better quality of life"], ["More tax revenue", "government can spend on health education infrastructure"], ["Improved healthcare", "life expectancy rises / infant mortality falls / people live longer"], ["More employment", "jobs created / incomes rise"]]], "concept": "Syllabus 5.1. Economic growth and development." },

  // ═══════════════════════════════════════════════════════════════
  // SYLLABUS 6: International trade and globalisation
  // ═══════════════════════════════════════════════════════════════
  { "id": "SBb_s6_free_trade", "case": "Thailand has signed free trade agreements with several countries. Tariffs on many goods have been reduced or removed. Thai exports of electronics and vehicles have grown.", "q": "Explain two benefits of free trade for an economy.", "ans": [[["Greater specialisation", "countries produce what they are best at / comparative advantage / higher efficiency"], ["Lower prices for consumers", "competition from imports / access to cheaper goods"], ["Larger markets for exporters", "sell more abroad / economies of scale / higher sales"], ["Greater choice", "wider variety of goods and services"]], [["Greater specialisation", "countries produce what they are best at / comparative advantage / higher efficiency"], ["Lower prices for consumers", "competition from imports / access to cheaper goods"], ["Larger markets for exporters", "sell more abroad / economies of scale / higher sales"], ["Greater choice", "wider variety of goods and services"]]], "concept": "Syllabus 6.2.3. Benefits of free trade." },
  { "id": "SBb_s6_MNC_benefits", "case": "A Japanese car manufacturer opened a factory in Mexico, employing 3,000 local workers. The firm provided training in robotics. The factory exports cars to the US.", "q": "Explain two benefits of multinational companies for a host country.", "ans": [[["Create employment", "hire local workers / reduce unemployment / increase incomes"], ["Bring investment / capital", "build factories / add to capital stock / boost productive capacity"], ["Transfer technology and skills", "training / know-how / raises productivity of labour"], ["Increase exports", "output sold abroad / improves current account"]], [["Create employment", "hire local workers / reduce unemployment / increase incomes"], ["Bring investment / capital", "build factories / add to capital stock / boost productive capacity"], ["Transfer technology and skills", "training / know-how / raises productivity of labour"], ["Increase exports", "output sold abroad / improves current account"]]], "concept": "Syllabus 6.2.2. MNC benefits." },
  { "id": "SBb_s6_exchange_rate", "case": "The UK pound depreciated against the US dollar in 2022. British exporters reported higher overseas sales. The cost of imported fuel and raw materials rose.", "q": "Explain two effects of a depreciation of the exchange rate on an economy.", "ans": [[["Exports become cheaper / more competitive", "foreign buyers pay less / demand for exports rises / may improve current account"]], [["Imports become more expensive", "higher costs for imported goods / cost-push inflation / firms using imported inputs face higher costs"]]], "concept": "Syllabus 6.3.4. Consequences of exchange rate fluctuations." },
  { "id": "SBb_s6_protection", "case": "India raised tariffs on imported electronic goods in 2019. The government argued it was protecting domestic producers. Critics said it raised prices for consumers.", "q": "Explain two reasons why a government may impose protection.", "ans": [[["Protect infant industry", "new firms need time to develop / cannot compete with established foreign firms yet"], ["Protect jobs / declining industry", "prevent job losses / save employment in struggling sectors"], ["Prevent dumping", "foreign firms selling below cost / unfair competition"], ["Strategic industry", "e.g. defence / agriculture - essential for national security"]], [["Protect infant industry", "new firms need time to develop / cannot compete with established foreign firms yet"], ["Protect jobs / declining industry", "prevent job losses / save employment in struggling sectors"], ["Prevent dumping", "foreign firms selling below cost / unfair competition"], ["Strategic industry", "e.g. defence / agriculture - essential for national security"]]], "concept": "Syllabus 6.2.5. Reasons for protection." },
  { "id": "SBb_s6_specialisation", "case": "Brazil produces mainly coffee, sugar cane and soya. It concentrates on these goods because it has the climate and land to produce them efficiently. Colombia specialises in coffee while Saudi Arabia specialises in oil.", "q": "Explain two benefits of specialisation for an economy.", "ans": [[["Higher output / efficiency", "produce what best at / comparative advantage / more from same resources"], ["Lower average cost", "specialisation allows economies of scale / division of labour"], ["Higher quality", "focus on narrow range / become expert / better product"]], [["Higher output / efficiency", "produce what best at / comparative advantage / more from same resources"], ["Lower average cost", "specialisation allows economies of scale / division of labour"], ["Higher quality", "focus on narrow range / become expert / better product"]]], "concept": "Syllabus 6.1.1. Benefits of specialisation." },
  { "id": "SBb_s6_appreciation", "case": "The Swiss franc appreciated against the euro. Swiss exporters found it harder to sell abroad. Swiss consumers benefited from cheaper imports.", "q": "Explain two effects of an appreciation of the exchange rate on an economy.", "ans": [[["Exports become more expensive / less competitive", "foreign buyers pay more / demand for exports falls / may worsen current account"]], [["Imports become cheaper", "lower costs for imported goods / may reduce inflation / consumers benefit"]]], "concept": "Syllabus 6.3.4. Appreciation effects." },
  { "id": "SBb_s6_MNC_disadvantages", "case": "A multinational company opened a factory in Bangladesh. It paid low wages and repatriated most profits to its home country. Some local firms were forced to close.", "q": "Explain two disadvantages of multinational companies for a host country.", "ans": [[["Repatriate profits", "profits sent abroad / no benefit to host country / capital outflow"], ["May exploit labour", "low wages / poor conditions / use market power"], ["Damage local firms", "competition may force closures / job losses in domestic firms"], ["Environmental damage", "may pollute / ignore local regulations"]], [["Repatriate profits", "profits sent abroad / no benefit to host country / capital outflow"], ["May exploit labour", "low wages / poor conditions / use market power"], ["Damage local firms", "competition may force closures / job losses in domestic firms"], ["Environmental damage", "may pollute / ignore local regulations"]]], "concept": "Syllabus 6.2.2. MNC disadvantages." },
  { "id": "SBb_s6_tariff_effects", "case": "The US imposed higher tariffs on some Chinese imports. These were expected to change the US current account balance, output and tax revenue. The US had a current account deficit of $470 billion in 2020.", "q": "Explain two effects of imposing a tariff on imports.", "ans": [[["Raise price of imports", "consumers pay more / may reduce demand for imports"], ["Protect domestic firms", "reduce competition / domestic producers sell more"], ["Raise government revenue", "tariff is a tax / government earns from duties"], ["May improve current account", "fewer imports / reduce deficit"]], [["Raise price of imports", "consumers pay more / may reduce demand for imports"], ["Protect domestic firms", "reduce competition / domestic producers sell more"], ["Raise government revenue", "tariff is a tax / government earns from duties"], ["May improve current account", "fewer imports / reduce deficit"]]], "concept": "Syllabus 6.2.4. Effects of tariffs." },
];
